      readonly status: "action_dispatched";
      readonly action: RunAction;
      readonly preventDefault: true;
    }
  | {
      readonly status: "confirm_required";
      readonly confirm: PendingConfirm;
      readonly preventDefault: true;
    }
  | {
      readonly status: "travel_stopped";
      readonly reason: string;
      readonly preventDefault: true;
    }
  | {
      readonly status: "input_locked";
      readonly preventDefault: true;
    };

export type InputDispatchSnapshot = {
  readonly gameState: GameState | null;
  readonly ui: UiSlice;
};

export type InputDispatchDeps = {
  readonly dispatchAction: (action: RunAction) => void;
  readonly patchUi: (patch: Partial<UiSlice>) => void;
  readonly appendInputFeedback: (
    actionKind: InputFeedbackActionKind,
    reason: string,
  ) => void;
  readonly lockInput: () => void;
};

export const dispatchGameKey = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
  keyPress: GameKeyPress,
): InputDispatchResult => {
  const context = inputFocusContext(snapshot.ui);
  const binding = resolveKeyBinding(keyPress.key, context);

  if (binding === null) {
    return {
      status: "ignored",
      reason: `unbound key in ${context}`,
      preventDefault: false,
    };
  }

  const intent = binding.intent;

  if (
    snapshot.ui.inputLocked &&
    intent.kind === "run_action"
  ) {
    return { status: "input_locked", preventDefault: true };
  }

  switch (intent.kind) {
    case "run_action":
      return dispatchRunAction(snapshot, deps, intent.action, keyPress);
    case "set_context_mode":
      deps.patchUi({
        contextPanelMode:
          snapshot.ui.contextPanelMode === intent.mode ? "inspect" : intent.mode,
      });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "toggle_diary":
      deps.patchUi({
        diaryOpen: !snapshot.ui.diaryOpen,
        artifactOpen: false,
      });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "open_keymap":
      deps.patchUi({ keymapOpen: true });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "close_keymap":
      deps.patchUi({ keymapOpen: false });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "close_top":
      closeTop(snapshot, deps);
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "request_abort":
      return requestAbortConfirm(snapshot, deps);
    case "confirm_yes":
      return confirmPending(snapshot, deps);
    case "confirm_no":
      cancelPendingConfirm(snapshot, deps);
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
  }
};

export const inputFocusContext = (ui: UiSlice): KeyBindingContext => {
  if (ui.keymapOpen) {
    return "overlay";
  }

  if (ui.diaryOpen || ui.artifactOpen) {
    return "paused-layer";
  }

  if (ui.pendingConfirm !== null) {
    return "confirm";
  }

  return "play";
};

export const dangerousConfirmForAction = (
  state: GameState,
  action: RunAction,
): PendingConfirm | null => {
  if (action.kind !== "descend" || !isPlayerAction(action)) {
    return null;
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return null;
  }

  const adjacentEnemy = adjacentEnemies(state)[0];
  if (adjacentEnemy === undefined) {
    return null;
  }

  return {
    action,
    prompt: `Enemy ${adjacentEnemy.id} is adjacent. Descend anyway? y/n`,
  };
};

const dispatchRunAction = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
  action: RunAction,
  keyPress: GameKeyPress,
): InputDispatchResult => {
  if (snapshot.gameState === null) {
    return {
      status: "ignored",
      reason: "game state not ready",
      preventDefault: false,
    };
  }

  if (keyPress.repeat === true && action.kind !== "move") {
    return {
      status: "ignored",
      reason: "non-move key repeat ignored",
      preventDefault: false,
    };
  }

  if (keyPress.repeat === true && action.kind === "move") {
    const stop = autoTravelStopFor(snapshot.gameState);
    if (stop !== null) {
      deps.appendInputFeedback("move", stop.message);
      return {
        status: "travel_stopped",
        reason: stop.reason,
        preventDefault: true,
      };
    }
  }

  const confirm = dangerousConfirmForAction(snapshot.gameState, action);
  if (confirm !== null) {
    deps.patchUi({ pendingConfirm: confirm });
    return {
      status: "confirm_required",
      confirm,
      preventDefault: true,
    };
  }

  deps.dispatchAction(action);
  deps.lockInput();

  return {
    status: "action_dispatched",
    action,
    preventDefault: true,
  };
};

const confirmPending = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
): InputDispatchResult => {
  const pending = snapshot.ui.pendingConfirm;
  if (pending === null) {
    return {
      status: "ignored",
      reason: "no pending confirm",
      preventDefault: false,
    };
  }

  deps.patchUi({ pendingConfirm: null });
  deps.dispatchAction(pending.action);

    }),
    arrivalIntroLine: null
  });

  void resolveTransitionFloor({
    get,
    set,
    session: gameSession,
    depth: nextDepth,
    startedAtMs
  });
};

const resolveTransitionFloor = async ({
  get,
  set,
  session,
  depth,
  startedAtMs
}: {
  readonly get: StoreGet;
  readonly set: StoreSet;
  readonly session: ClientGameSession;
  readonly depth: number;
  readonly startedAtMs: number;
}): Promise<void> => {
  const controllerState = await session.pollFloor(depth);
  patchCurrentTransition(get, set, {
    controllerState: controllerStateForStore(controllerState)
  });

  const served = await session.resolveFloor(depth);
  const readyAtMs = nowMs();
  const transition = get().transition;
  if (
    transition === null ||
    transition.phase !== "descending" ||
    transition.depth !== depth ||
    transition.startedAtMs !== startedAtMs
  ) {
    return;
  }

  set({
    transition: markTransitionFloorReady(transition, readyAtMs, served.source)
  });
  completeArrivalWhenReady(get, set);

  const next = get().transition;
  if (next === null) {
    return;
  }

  if (shouldAutoEnterFloor(next, nowMs())) {
    enterResolvedFloor(get, set);
    return;
  }

  const delayMs = Math.max(0, READY_THEATER_MS - (nowMs() - next.startedAtMs));
  globalThis.setTimeout(() => {
    const current = get().transition;
    if (current !== null && shouldAutoEnterFloor(current, nowMs())) {
      enterResolvedFloor(get, set);
    }
  }, delayMs);
};

const enterResolvedFloor = (get: StoreGet, set: StoreSet): void => {
  void enterResolvedFloorAsync(get, set);
};

const enterResolvedFloorAsync = async (
  get: StoreGet,
  set: StoreSet
): Promise<void> => {
  const { gameSession, transition } = get();
  if (
    gameSession === null ||
    transition === null ||
    transition.phase !== "descending" ||
    !transition.floorReady
  ) {
    return;
  }

  const stepped = await stepResolvedFloor(get, set, gameSession, transition);
  if (stepped === null) {
    return;
  }

  const { result, transition: servedTransition } = stepped;
  const arrivalStartedAtMs = nowMs();
  const arrivalTransition = startArrivalRitual(
    servedTransition,
    arrivalStartedAtMs
  );
  const introLine = floorIntroFromState(result.state);
  const latencySample = transitionLatencySample(
    result.state,
    arrivalTransition,
    arrivalStartedAtMs
  );
  persistActiveRun(gameSession);
  gameSession.prefetchNextFloor();

  set({
    gameState: result.state,
    activeRun: activeRunFromSession(gameSession),
    transition: arrivalTransition,
    arrivalIntroLine: introLine,
    latencySamples: [...get().latencySamples, latencySample],
    ui: { ...get().ui, inputLocked: true, pendingConfirm: null }
  });

  scheduleArrivalCompletion(get, set);
};

const stepResolvedFloor = async (
  get: StoreGet,
  set: StoreSet,
  gameSession: ClientGameSession,
  transition: FloorTransitionState
): Promise<{
  readonly result: ClientGameSessionStep;
  readonly transition: FloorTransitionState;
} | null> => {
  try {
    return {
      result: gameSession.step({ kind: "descend" }),
      transition
    };
  } catch {
    const current = get().transition;
    if (!sameDescendingTransition(current, transition)) {
      return null;
    }

    const fallback = await resolveFallbackAfterEntryFailure(
      gameSession,
      transition.depth
    );
    if (fallback === null) {
      clearFailedTransition(get, set);
      return null;
    }

    if (fallback.source !== "fallback") {
      clearFailedTransition(get, set);
      return null;
    }

    gameSession.setServedFloor(fallback);

    const recovered = get().transition;
    if (!sameDescendingTransition(recovered, transition)) {
      return null;
    }

    const fallbackTransition = markTransitionFloorReady(
      recovered,
      recovered.readyAtMs ?? nowMs(),
      "fallback"
    );
    set({ transition: fallbackTransition });

    try {
      return {
        result: gameSession.step({ kind: "descend" }),
        transition: fallbackTransition
      };
    } catch {
      clearFailedTransition(get, set);
      return null;
    }
  }
};

const resolveFallbackAfterEntryFailure = async (
  gameSession: ClientGameSession,
  depth: number
): Promise<Awaited<ReturnType<ClientGameSession["resolveFloor"]>> | null> => {
  try {
    return await gameSession.resolveFloor(depth);
  } catch {
    return null;
  }
};

const clearFailedTransition = (get: StoreGet, set: StoreSet): void => {
  set({
    transition: null,
    arrivalIntroLine: null,
    ui: { ...get().ui, inputLocked: false }
  });
};

const sameDescendingTransition = (
  current: FloorTransitionState | null,
  expected: FloorTransitionState
): current is FloorTransitionState =>
  current !== null &&
  current.phase === "descending" &&
  expected.phase === "descending" &&
  current.depth === expected.depth &&
  current.startedAtMs === expected.startedAtMs;

const finishArrival = (get: StoreGet, set: StoreSet): boolean => {
  const { transition } = get();
  if (
    transition === null ||
    transition.phase !== "arrival" ||
    transition.servedSource === null
  ) {
    return false;
  }

  set({
    transition: null,
    arrivalIntroLine: null,
    ui: { ...get().ui, inputLocked: false }
  });
  return true;
};

const completeArrivalWhenReady = (get: StoreGet, set: StoreSet): boolean => {
  const current = get().transition;
  if (current === null || !shouldResumePlay(current, nowMs())) {
    return false;
  }

  return finishArrival(get, set);
};

const scheduleArrivalCompletion = (get: StoreGet, set: StoreSet): void => {
  if (completeArrivalWhenReady(get, set)) {
    return;
  }

  const transition = get().transition;
  if (transition === null || transition.phase !== "arrival") {
    return;
  }

  const currentMs = nowMs();
  const delayMs =
    transition.playableAtMs !== null && transition.playableAtMs > currentMs
      ? transition.playableAtMs - currentMs
      : ARRIVAL_COMPLETION_RETRY_MS;

  globalThis.setTimeout(() => {
    const current = get().transition;
    if (!sameArrivalTransition(current, transition)) {
      return;
    }

    scheduleArrivalCompletion(get, set);
  }, delayMs);
};

const sameArrivalTransition = (
  current: FloorTransitionState | null,
  expected: FloorTransitionState
): boolean =>
  current !== null &&
  current.phase === "arrival" &&
  expected.phase === "arrival" &&
  current.depth === expected.depth &&
  current.startedAtMs === expected.startedAtMs &&
  current.arrivalStartedAtMs === expected.arrivalStartedAtMs;

const transitionLatencySample = (
  state: GameState,
  transition: FloorTransitionState,
  recordedAtMs: number
): TransitionLatencySample => ({
  runId: state.run.runId,
  fromDepth: Math.max(1, transition.depth - 1),
  toDepth: transition.depth,
  stairsToPlayableMs: Math.round(recordedAtMs - transition.startedAtMs),
  controllerState: transition.controllerState,
  servedSource: transition.servedSource ?? "fallback",
  recordedAtMs
});

const patchCurrentTransition = (
  get: StoreGet,
  set: StoreSet,
  patch: Partial<FloorTransitionState>
): void => {
  const transition = get().transition;
  if (transition === null) {
    return;
  }

  set({ transition: { ...transition, ...patch } });
};

const controllerStateForStore = (
  state: "ready" | "in_flight" | "none"
): FloorControllerState => state;

const persistAfterStep = (
  session: ClientGameSession,
  state: GameState,
  set: StoreSet
): void => {
  if (state.run.terminalStatus === "ACTIVE") {
    persistActiveRun(session);
    set({
      gameState: state,
      activeRun: activeRunFromSession(session)
    });
    return;
  }

  const storage = browserStorage();
  const entry = runIndexEntryFromState({
    state,
    createdAt: session.createdAt,
    traceContent: session.traceContent
  });
  const runIndex = upsertRunIndexEntry(storage, entry);
  clearActiveRun(storage);
  set({
    gameState: state,
    activeRun: null,
    runIndex,
    terminalRun: state,
    screen: "title",
    ui: defaultUi
  });
};

const persistActiveRun = (session: ClientGameSession): void => {
  saveActiveRun(browserStorage(), activeRunFromSession(session));
};

const activeRunFromSession = (session: ClientGameSession): ActiveRunRecord => ({
  runId: session.state.run.runId,
  seed: session.state.run.seed,
  createdAt: session.createdAt,
  gameState: session.state,
  traceContent: session.traceContent
});

const browserStorage = (): Storage | null =>
  typeof window === "undefined" ? null : window.localStorage;

const nowMs = (): number =>
  typeof performance === "undefined" ? Date.now() : performance.now();

