export const clampIndex = (index: number, length: number): number => {
  if (length <= 0) {
    return 0;
  }

  return ((index % length) + length) % length;
};

export const menuNumber = (key: string): number | null => {
  if (!/^[1-9]$/u.test(key)) {
    return null;
  }

  return Number.parseInt(key, 10) - 1;
};

