 754	function requeryExpressiblePolicyAction(
 755	  state: GameState,
 756	  view: BotStateView,
 757	  unsupportedAction: RunAction,
 758	  policyState: BotPolicyState
 759	): RequeriedAction | null {
 760	  const unsupportedKey = actionKey(unsupportedAction);
 761	  const constrainedView: BotStateView = {
 762	    ...view,
 763	    availableActions: view.availableActions.filter(
 764	      (candidate) =>
 765	        actionKey(candidate) !== unsupportedKey &&
 766	        keySequenceForAction(state, candidate, policyState.inventoryIndex) !== null
 767	    )
 768	  };
 769	
 770	  if (constrainedView.availableActions.length === 0) {
 771	    return null;
 772	  }
 773	
 774	  const retryAction = legalizePolicyDecision(
 775	    constrainedView,
 776	    balancedPolicy.decide(constrainedView)
 777	  );
 778	  const retryMapping = mapPolicyActionToKeys(state, retryAction, policyState);
 779	  if (retryMapping === null) {
 780	    return null;
 781	  }
 782	
 783	  return {
 784	    action: retryAction,
 785	    actionLabel: `policy-requery:${retryMapping.action}`,
 786	    keys: retryMapping.keys
 787	  };
 788	}
