 882	function inventorySelectionKeys(
 883	  currentIndex: number,
 884	  targetIndex: number,
 885	  entryCount: number
 886	): readonly string[] {
 887	  if (entryCount <= 0 || currentIndex === targetIndex) {
 888	    return [];
 889	  }
 890	
 891	  const normalizedCurrent = ((currentIndex % entryCount) + entryCount) % entryCount;
 892	  const normalizedTarget = ((targetIndex % entryCount) + entryCount) % entryCount;
 893	  const down = (normalizedTarget - normalizedCurrent + entryCount) % entryCount;
 894	  const up = (normalizedCurrent - normalizedTarget + entryCount) % entryCount;
 895	
 896	  return Array.from(
 897	    { length: Math.min(down, up) },
 898	    () => (down <= up ? "ArrowDown" : "ArrowUp")
 899	  );
 900	}
