 902	function directionBetweenPositions(
 903	  from: { readonly x: number; readonly y: number },
 904	  to: { readonly x: number; readonly y: number }
 905	): Direction | null {
 906	  const dx = Math.sign(to.x - from.x);
 907	  const dy = Math.sign(to.y - from.y);
 908	  if (dx === 0 && dy === 0) {
 909	    return null;
 910	  }
 911	  if (Math.abs(to.x - from.x) > 1 || Math.abs(to.y - from.y) > 1) {
 912	    return null;
 913	  }
 914	  return deltaToDirection(dx, dy);
 915	}
